module width_8to16
(
    input clk,
    input rst_n,
    input valid_in,
    input [7:0] data_in,
    output valid_out,
    output [15:0] data_out
);

reg[1:0] state;
parameter state_idle = 0;
parameter state_1st = 1;
parameter state_2nd = 2;
reg[7:0] data_lock;
reg valid_out_reg;
reg[15:0] data_out_reg;
always@(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        data_out_reg <= 16'd0;
    end else begin
        if(valid_in) begin
            if(state == state_idle) begin
                data_lock <= data_in;
                state <= state_1st;
            end else if(state == state_1st) begin
                data_lock <= data_in;
                state <= state_2nd;
                valid_out_reg <= 1'b1;
                data_out_reg <= {data_lock, data_in};
            end else if(state == state_2nd) begin
                data_lock <= data_in;
                state <= state_1st;
                valid_out_reg <= 1'b1;
                data_out_reg <= {data_lock, data_in};
            end
        end else begin
            valid_out_reg <= 1'b0;
            data_out_reg <= 16'd0;
        end
    end
end
assign valid_out = valid_out_reg;
assign data_out = data_out_reg;
endmodule
